import undetected_chromedriver as ucimport jsonimport timeoptions = uc.ChromeOptions()driver = uc.Chrome(options=options)driver.get("https://flightpass.royalairmaroc.com")input("🔐 Please log in manually, then press Enter...")# Save cookieswith open("cookies.json", "w") as f:    json.dump(driver.get_cookies(), f)print("✅ Cookies saved.")# Save localStoragelocal_storage = driver.execute_script("return window.localStorage;")with open("local_storage.json", "w") as f:    json.dump(local_storage, f)print("✅ LocalStorage saved.")# Save sessionStoragesession_storage = driver.execute_script("return window.sessionStorage;")with open("session_storage.json", "w") as f:    json.dump(session_storage, f)print("✅ SessionStorage saved.")driver.quit()